1	// Package store implements the three-scope markdown-backed knowledge store.
2	//
3	// The store is the only component that reads and writes markdown files on
4	// disk. Every path that produces or consumes an Entry goes through it.
5	// Other packages (search, mcp, extraction) must not touch the filesystem
6	// for store content directly.
7	//
8	// Responsibilities:
9	//   - Locate the three scope roots via Config.
10	//   - Glob and load entries from the live and pending directories.
11	//   - Enforce the pending/ invariant: all Writes go to <scope>/pending/,
12	//     never directly to the live directory. Entries reach the live
13	//     directory only via Promote.
14	//   - Prune stale pending entries (older than PendingTTL) silently.
15	//   - Walk-up project root detection (FindProjectRoot).
16	//
17	// Non-responsibilities:
18	//   - Search and FTS indexing (see internal/search).
19	//   - Frontmatter parsing and validation (see internal/format).
20	//   - Sync and git operations (git is run by the user, not by mastermind).
21	package store
22	
23	import (
24		"errors"
25		"fmt"
26		"io/fs"
27		"os"
28		"path/filepath"
29		"sort"
30		"strings"
31		"time"
32		"unicode"
33	
34		"github.com/jeanfbrito/mastermind/internal/format"
35	)
36	
37	// ErrInvalidScope is returned when a caller passes a scope value that
38	// isn't one of the three known scopes, or passes a scope for which the
39	// store has no root configured.
40	var ErrInvalidScope = errors.New("store: invalid or unconfigured scope")
41	
42	// ErrEntryExists is returned when Promote would overwrite a live entry.
43	// The caller must decide whether to force, rename, or reject.
44	var ErrEntryExists = errors.New("store: target entry already exists")
45	
46	// Store reads and writes entries across the three scopes described in
47	// Config. Store is safe for use by a single goroutine; concurrent writes
48	// to the same path are not coordinated (filesystem atomics cover the
49	// single-writer case, which is all mastermind needs).
50	type Store struct {
51		cfg Config
52	}
53	
54	// New constructs a Store from the given Config. It does NOT create any
55	// directories on disk — that happens lazily on the first write to each
56	// scope. Read-only callers (search, list) should never cause directory
57	// creation.
58	func New(cfg Config) *Store {
59		if cfg.Now == nil {
60			cfg.Now = time.Now
61		}
62		return &Store{cfg: cfg}
63	}
64	
65	// Config returns a copy of the store's configuration. Useful for tests
66	// and for components that need to know which roots are active.
67	func (s *Store) Config() Config {
68		return s.cfg
69	}
70	
71	// EntryRef is a lightweight handle to an entry on disk. It contains the
72	// frontmatter metadata and the absolute file path, but not the body.
73	// Listing operations return EntryRefs so callers can filter and sort
74	// without paying the cost of loading every body into memory.
75	//
76	// Load a full Entry with (*Store).LoadRef.
77	type EntryRef struct {
78		Path     string          // absolute path to the .md file
79		Metadata format.Metadata // parsed frontmatter (not yet Normalized)
80		Scope    format.Scope    // which scope this ref was found in
81		Pending  bool            // true if the ref lives in <scope>/pending/
82	}
83	
84	// FindProjectRoot walks upward from cwd looking for the nearest directory
85	// containing a .mm/ subdirectory. Returns the absolute path of the repo
86	// root (the directory containing .mm/), or "" if nothing is found before
87	// reaching the filesystem root.
88	//
89	// This is used by session-start and session-close to locate the
90	// project-shared store without requiring the user to pass a path.
91	func FindProjectRoot(cwd string) string {
92		if cwd == "" {
93			return ""
94		}
95		abs, err := filepath.Abs(cwd)
96		if err != nil {
97			return ""
98		}
99	
100		// Walk upward. filepath.Dir on a root path returns the root itself,
101		// so compare before/after to detect the top.
102		for {
103			candidate := filepath.Join(abs, ".mm")
104			if info, err := os.Stat(candidate); err == nil && info.IsDir() {
105				return abs
106			}
107			parent := filepath.Dir(abs)
108			if parent == abs {
109				return ""
110			}
111			abs = parent
112		}
113	}
114	
115	// Write stores a new pending entry under the appropriate scope.
116	//
117	// The scope comes from entry.Metadata.Scope — callers MUST set it before
118	// calling Write. If the scope is empty or unknown, Write returns
119	// ErrInvalidScope. This is the single chokepoint that enforces the
120	// pending/ invariant: there is no path from Write to the live directory.
121	//
122	// The file is written atomically (tempfile + rename in the same
123	// directory). The returned path is absolute and points at the freshly
124	// written pending file.
125	func (s *Store) Write(entry *format.Entry) (string, error) {
126		if entry == nil {
127			return "", fmt.Errorf("store: write: nil entry")
128		}
129		// Normalize before writing so defaults land on disk.
130		entry.Normalize()
131	
132		scope := scopeFromFormat(entry.Metadata.Scope)
133		root := s.cfg.rootFor(scope)
134		if scope == scopeUnknown || root == "" {
135			return "", fmt.Errorf("%w: %q", ErrInvalidScope, entry.Metadata.Scope)
136		}
137	
138		pendingPath := filepath.Join(root, pendingDirName)
139		if err := os.MkdirAll(pendingPath, 0o755); err != nil {
140			return "", fmt.Errorf("store: mkdir pending: %w", err)
141		}
142	
143		name := pendingFileName(s.cfg.Now(), entry.Metadata.Topic)
144		target := filepath.Join(pendingPath, name)
145	
146		data, err := entry.MarshalMarkdown()
147		if err != nil {
148			return "", fmt.Errorf("store: marshal entry: %w", err)
149		}
150	
151		if err := writeFileAtomic(target, data); err != nil {
152			return "", fmt.Errorf("store: atomic write %s: %w", target, err)
153		}
154		return target, nil
155	}
156	
157	// Promote moves a pending entry to the live directory of its scope.
158	// pendingPath must be an absolute path to a file under one of the
159	// configured <scope>/pending/ directories.
160	//
161	// The destination filename is derived from the entry's topic (the
162	// timestamp prefix used in pending/ is stripped). If a file with the
163	// target name already exists, Promote returns ErrEntryExists — callers
164	// must decide whether to rename, force, or reject.
165	//
166	// Promote is not atomic in the filesystem sense — it does two operations
167	// (load + rename), and a crash between them leaves the entry in pending/,
168	// which is the safe side to fail on.
169	func (s *Store) Promote(pendingPath string) (string, error) {
170		abs, err := filepath.Abs(pendingPath)
171		if err != nil {
172			return "", fmt.Errorf("store: abs %s: %w", pendingPath, err)
173		}
174	
175		// Figure out which scope this path belongs to by matching roots.
176		scope, root := s.scopeOfPath(abs)
177		if scope == scopeUnknown {
178			return "", fmt.Errorf("%w: path not under any configured scope: %s", ErrInvalidScope, abs)
179		}
180	
181		// Confirm it's actually a pending file, not a live one.
182		if !strings.Contains(abs, string(os.PathSeparator)+pendingDirName+string(os.PathSeparator)) {
183			return "", fmt.Errorf("store: promote: path is not in pending/: %s", abs)
184		}
185	
186		// Load the entry so we can derive the live filename from its topic.
187		data, err := os.ReadFile(abs)
188		if err != nil {
189			return "", fmt.Errorf("store: read pending: %w", err)
190		}
191		entry, err := format.Parse(data)
192		if err != nil {
193			return "", fmt.Errorf("store: parse pending %s: %w", abs, err)
194		}
195	
196		liveDirPath := filepath.Join(root, liveDir(scope))
197		if err := os.MkdirAll(liveDirPath, 0o755); err != nil {
198			return "", fmt.Errorf("store: mkdir live: %w", err)
199		}
200	
201		name := liveFileName(entry.Metadata.Topic)
202		target := filepath.Join(liveDirPath, name)
203	
204		if _, err := os.Stat(target); err == nil {
205			return "", fmt.Errorf("%w: %s", ErrEntryExists, target)
206		} else if !errors.Is(err, fs.ErrNotExist) {
207			return "", fmt.Errorf("store: stat target: %w", err)
208		}
209	
210		if err := os.Rename(abs, target); err != nil {
211			return "", fmt.Errorf("store: rename %s -> %s: %w", abs, target, err)
212		}
213		return target, nil
214	}
215	
216	// ListPending returns all pending refs across the given scope. If the
217	// scope's root isn't configured, returns nil, nil (not an error — some
218	// scopes are legitimately unavailable in some sessions).
219	//
220	// Order: sorted by path ascending, which (given the pendingFileName
221	// timestamp prefix) also yields chronological order.
222	func (s *Store) ListPending(scope format.Scope) ([]EntryRef, error) {
223		sk := scopeFromFormat(scope)
224		root := s.cfg.rootFor(sk)
225		if sk == scopeUnknown {
226			return nil, fmt.Errorf("%w: %q", ErrInvalidScope, scope)
227		}
228		if root == "" {
229			return nil, nil
230		}
231		dir := filepath.Join(root, pendingDirName)
232		return s.listDir(dir, scope, true)
233	}
234	
235	// ListLive returns all live (promoted) refs for the given scope.
236	// Same semantics as ListPending: unconfigured scopes return nil, nil.
237	func (s *Store) ListLive(scope format.Scope) ([]EntryRef, error) {
238		sk := scopeFromFormat(scope)
239		root := s.cfg.rootFor(sk)
240		if sk == scopeUnknown {
241			return nil, fmt.Errorf("%w: %q", ErrInvalidScope, scope)
242		}
243		if root == "" {
244			return nil, nil
245		}
246		dir := filepath.Join(root, liveDir(sk))
247		return s.listDir(dir, scope, false)
248	}
249	
250	// LoadRef reads the full entry body from a ref and returns a complete
251	// format.Entry with metadata re-parsed (so the returned entry is
252	// authoritative for both frontmatter and body).
253	func (s *Store) LoadRef(ref EntryRef) (*format.Entry, error) {
254		data, err := os.ReadFile(ref.Path)
255		if err != nil {
256			return nil, fmt.Errorf("store: read %s: %w", ref.Path, err)
257		}
258		entry, err := format.Parse(data)
259		if err != nil {
260			return nil, fmt.Errorf("store: parse %s: %w", ref.Path, err)
261		}
262		return entry, nil
263	}
264	
265	// Reject deletes a pending entry. Used by the review flow when the user
266	// decides a candidate isn't worth keeping. Idempotent — a missing file
267	// is not an error.
268	func (s *Store) Reject(pendingPath string) error {
269		abs, err := filepath.Abs(pendingPath)
270		if err != nil {
271			return fmt.Errorf("store: abs %s: %w", pendingPath, err)
272		}
273		scope, _ := s.scopeOfPath(abs)
274		if scope == scopeUnknown {
275			return fmt.Errorf("%w: path not under any configured scope: %s", ErrInvalidScope, abs)
276		}
277		if !strings.Contains(abs, string(os.PathSeparator)+pendingDirName+string(os.PathSeparator)) {
278			return fmt.Errorf("store: reject: path is not in pending/: %s", abs)
279		}
280		if err := os.Remove(abs); err != nil && !errors.Is(err, fs.ErrNotExist) {
281			return fmt.Errorf("store: remove %s: %w", abs, err)
282		}
283		return nil
284	}
285	
286	// PruneStale deletes every pending entry across all configured scopes
287	// whose modification time is older than PendingTTL. Returns the number
288	// of files removed.
289	//
290	// This is the "no guilt queue" enforcement: pending entries that sit
291	// unreviewed for a week are silently dropped. The caller (typically
292	// main on startup) never reports the count to the user.
293	func (s *Store) PruneStale() (int, error) {
294		cutoff := s.cfg.Now().Add(-PendingTTL)
295		var removed int
296	
297		for _, scope := range []format.Scope{
298			format.ScopeUserPersonal,
299			format.ScopeProjectShared,
300			format.ScopeProjectPersonal,
301		} {
302			refs, err := s.ListPending(scope)
303			if err != nil {
304				return removed, err
305			}
306			for _, ref := range refs {
307				info, err := os.Stat(ref.Path)
308				if err != nil {
309					if errors.Is(err, fs.ErrNotExist) {
310						continue
311					}
312					return removed, fmt.Errorf("store: stat %s: %w", ref.Path, err)
313				}
314				if info.ModTime().Before(cutoff) {
315					if err := os.Remove(ref.Path); err != nil {
316						return removed, fmt.Errorf("store: remove stale %s: %w", ref.Path, err)
317					}
318					removed++
319				}
320			}
321		}
322		return removed, nil
323	}
324	
325	// ─── internal helpers ───────────────────────────────────────────────────
326	
327	// listDir reads a directory and returns refs for every .md file it
328	// contains. Missing directories return an empty slice, not an error —
329	// the store's scopes are legitimately sparse (not every scope exists
330	// in every session).
331	func (s *Store) listDir(dir string, scope format.Scope, pending bool) ([]EntryRef, error) {
332		ents, err := os.ReadDir(dir)
333		if err != nil {
334			if errors.Is(err, fs.ErrNotExist) {
335				return nil, nil
336			}
337			return nil, fmt.Errorf("store: read dir %s: %w", dir, err)
338		}
339	
340		var refs []EntryRef
341		for _, ent := range ents {
342			if ent.IsDir() {
343				continue
344			}
345			name := ent.Name()
346			if !strings.HasSuffix(name, ".md") {
347				continue
348			}
349			fullPath := filepath.Join(dir, name)
350			data, err := os.ReadFile(fullPath)
351			if err != nil {
352				return nil, fmt.Errorf("store: read %s: %w", fullPath, err)
353			}
354			entry, err := format.Parse(data)
355			if err != nil {
356				// Skip malformed files; don't fail the entire list.
357				// The review flow and the search layer can both live
358				// with a malformed entry being invisible until fixed.
359				continue
360			}
361			refs = append(refs, EntryRef{
362				Path:     fullPath,
363				Metadata: entry.Metadata,
364				Scope:    scope,
365				Pending:  pending,
366			})
367		}
368	
369		sort.Slice(refs, func(i, j int) bool {
370			return refs[i].Path < refs[j].Path
371		})
372		return refs, nil
373	}
374	
375	// scopeOfPath identifies which configured scope a filesystem path belongs
376	// to, by prefix-matching against each configured root. Returns
377	// scopeUnknown if no root matches.
378	func (s *Store) scopeOfPath(path string) (scopeKind, string) {
379		for _, sk := range []scopeKind{scopeUser, scopeProjectShared, scopeProjectPersonal} {
380			root := s.cfg.rootFor(sk)
381			if root == "" {
382				continue
383			}
384			rootAbs, err := filepath.Abs(root)
385			if err != nil {
386				continue
387			}
388			// Normalize trailing separator for robust prefix match.
389			prefix := rootAbs + string(os.PathSeparator)
390			if strings.HasPrefix(path, prefix) || path == rootAbs {
391				return sk, root
392			}
393		}
394		return scopeUnknown, ""
395	}
396	
397	// writeFileAtomic writes data to path using the tempfile + rename
398	// pattern. The tempfile lives in the same directory as the target so
399	// rename is an atomic operation on the same filesystem.
400	func writeFileAtomic(path string, data []byte) error {
401		dir := filepath.Dir(path)
402		tmp, err := os.CreateTemp(dir, ".mm-tmp-*")
403		if err != nil {
404			return fmt.Errorf("create temp: %w", err)
405		}
406		tmpName := tmp.Name()
407		// If anything below fails, make a best-effort to remove the temp.
408		defer func() {
409			_ = os.Remove(tmpName)
410		}()
411	
412		if _, err := tmp.Write(data); err != nil {
413			tmp.Close()
414			return fmt.Errorf("write temp: %w", err)
415		}
416		if err := tmp.Sync(); err != nil {
417			tmp.Close()
418			return fmt.Errorf("sync temp: %w", err)
419		}
420		if err := tmp.Close(); err != nil {
421			return fmt.Errorf("close temp: %w", err)
422		}
423		if err := os.Rename(tmpName, path); err != nil {
424			return fmt.Errorf("rename temp: %w", err)
425		}
426		return nil
427	}
428	
429	// slugify turns a free-form topic string into a filesystem-safe slug.
430	// Lowercase, ASCII letters and digits only, dashes between words, no
431	// leading/trailing dashes, capped at 80 characters so filenames stay
432	// manageable.
433	//
434	// The slug is not meant to be unique on its own — pending files also
435	// get a timestamp prefix, and live files use the slug as the identity
436	// (so collisions are intentional deduplication).
437	func slugify(topic string) string {
438		var b strings.Builder
439		b.Grow(len(topic))
440		prevDash := false
441		for _, r := range strings.ToLower(topic) {
442			switch {
443			case unicode.IsLetter(r) && r < 128, unicode.IsDigit(r) && r < 128:
444				b.WriteRune(r)
445				prevDash = false
446			default:
447				if !prevDash && b.Len() > 0 {
448					b.WriteByte('-')
449					prevDash = true
450				}
451			}
452		}
453		s := strings.TrimRight(b.String(), "-")
454		if s == "" {
455			s = "untitled"
456		}
457		if len(s) > 80 {
458			s = strings.TrimRight(s[:80], "-")
459		}
460		return s
461	}
462	
463	// pendingFileName builds the canonical pending filename:
464	//
465	//	YYYYMMDD-HHMMSS-<slug>.md
466	//
467	// The timestamp prefix ensures chronological listing and makes
468	// accidental collisions vanishingly unlikely even for entries with the
469	// same topic.
470	func pendingFileName(now time.Time, topic string) string {
471		return fmt.Sprintf("%s-%s.md", now.UTC().Format("20060102-150405"), slugify(topic))
472	}
473	
474	// liveFileName builds the canonical live filename:
475	//
476	//	<slug>.md
477	//
478	// Live entries use slug as identity — the same topic always collides
479	// with itself, and Promote surfaces the collision to the caller via
480	// ErrEntryExists.
481	func liveFileName(topic string) string {
482		return slugify(topic) + ".md"
483	}
484

