	cwd, err := os.Getwd()
	if err != nil {
		return fmt.Errorf("get cwd: %w", err)
	}
	cfg, err := buildSessionConfig(cwd)
	if err != nil {
		return fmt.Errorf("build session config: %w", err)
	}

	s := store.New(cfg)

