func TestHandleWriteLandsInLive(t *testing.T) {
	srv, s := newTestServer(t)

	_, out, err := srv.handleWrite(context.Background(), nil, WriteInput{
		Topic:   "a new lesson",
		Body:    "the body of the lesson",
		Scope:   "user-personal",
		Kind:    "lesson",
		Project: "mastermind",
		Tags:    []string{"test"},
	})
